const express = require('express');
const winston = require('winston');
const morgan = require('morgan');
const path = require('path');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Sanitization function to prevent log injection
function sanitizeLogInput(input) {
  if (typeof input !== 'string') {
    input = String(input);
  }
  // Remove newlines, carriage returns, and other control characters
  return input.replace(/[\n\r\t\x00-\x1F\x7F]/g, '');
}

// Winston logger configuration with sanitization
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' }),
    new winston.transports.Console({
      format: winston.format.simple()
    })
  ]
});

// Custom morgan token for username with sanitization
morgan.token('username', (req) => {
  return req.body.username ? sanitizeLogInput(req.body.username) : 'anonymous';
});

// Custom morgan token for custom headers with sanitization
morgan.token('custom-header', (req) => {
  const header = req.headers['x-custom-header'];
  return header ? sanitizeLogInput(header) : 'none';
});

// Morgan middleware with custom format
app.use(morgan(':method :url :status :response-time ms - username: :username - ip: :remote-addr - custom-header: :custom-header', {
  stream: {
    write: (message) => {
      logger.info(sanitizeLogInput(message.trim()));
    }
  }
}));

// Audit logging endpoint
